#!/bin/bash
PROJECT_ROOT='/opt'
VENV_PATH="$PROJECT_ROOT/venv"
DB_NAME='password_manager'
DB_USER='postgres'
DB_PASS='S1st3mas'
ADMIN_EMAIL='admin@admin.com'
ADMIN_PASS='admin12345'
APP_PORT=8000 # Internal port for Uvicorn
echo '>>> Starting V5 (Self-Contained)...'
setsebool -P httpd_can_network_connect 1 || true
dnf install -y oracle-epel-release-el9
dnf install -y python39 python3-pip python3-devel gcc libffi-devel openssl-devel git firewalld postgresql-server postgresql-contrib nginx certbot python3-certbot-nginx -y
rm -f /etc/nginx/conf.d/default.conf
systemctl enable --now firewalld
firewall-cmd --permanent --add-service=http --add-service=https
firewall-cmd --permanent --add-port=8080/tcp
firewall-cmd --reload
if [ ! -f /var/lib/pgsql/data/PG_VERSION ]; then
    postgresql-setup --initdb || sudo -u postgres /usr/bin/initdb -D /var/lib/pgsql/data
fi
sed -i 's/ident/md5/g' /var/lib/pgsql/data/pg_hba.conf
systemctl restart postgresql
systemctl enable postgresql
sleep 3
cd /tmp
sudo -u postgres psql -c "ALTER USER postgres PASSWORD '$DB_PASS';"
sudo -u postgres psql -c "CREATE DATABASE $DB_NAME;" || true
echo '>>> Extracting code...'
mkdir -p $PROJECT_ROOT
cd $PROJECT_ROOT
base64 -d <<'EOF_CODE' > code.tar.gz

EOF_CODE
tar -xzf code.tar.gz
rm code.tar.gz
python3.9 -m venv $VENV_PATH
$VENV_PATH/bin/pip install --upgrade pip
echo '>>> Installing all Python dependencies...'
$VENV_PATH/bin/pip install --only-binary=:all: cryptography bcrypt==3.2.0 paramiko
$VENV_PATH/bin/pip install fastapi uvicorn sqlalchemy "psycopg[binary]" "passlib[bcrypt]" "python-jose[cryptography]" python-dotenv pydantic-settings pycryptodome python-multipart email-validator apscheduler

cat <<EOF > $PROJECT_ROOT/.env
APP_NAME=Kristoff API
DEBUG=true
DB_DRIVER=postgresql+psycopg
DB_HOST=localhost
DB_PORT=5432
DB_USER=$DB_USER
DB_PASSWORD=$DB_PASS
DB_NAME=$DB_NAME
JWT_SECRET_KEY=kristoff_secret_key_fixed_32_chars
JWT_ALGORITHM=HS256
JWT_ACCESS_TOKEN_EXPIRE_MINUTES=60
BOOTSTRAP_ADMIN_EMAIL=$ADMIN_EMAIL
BOOTSTRAP_ADMIN_PASSWORD=$ADMIN_PASS
AUTO_CREATE_TABLES=true
EOF

# BOOTSTRAP: Create initial groups in DB
echo ">>> Bootstrapping initial groups..."
systemctl start postgresql
sleep 2
sudo -u postgres psql -d $DB_NAME -c "CREATE TABLE IF NOT EXISTS predefined_groups (id SERIAL PRIMARY KEY, name TEXT UNIQUE NOT NULL);"
sudo -u postgres psql -d $DB_NAME -c "INSERT INTO predefined_groups (name) VALUES ('Sistemas'), ('Desarrollo'), ('Infraestructura'), ('DBA'), ('Seguridad') ON CONFLICT DO NOTHING;"

cat <<EOF > /etc/systemd/system/kristoff.service
[Unit]
Description=Kristoff Backend Service
After=network.target postgresql.service
[Service]
User=root
WorkingDirectory=$PROJECT_ROOT
EnvironmentFile=$PROJECT_ROOT/.env
Environment=PYTHONPATH=$PROJECT_ROOT
ExecStart=$VENV_PATH/bin/uvicorn main:app --host 127.0.0.1 --port $APP_PORT
Restart=always
RestartSec=5
[Install]
WantedBy=multi-user.target
EOF

systemctl daemon-reload
systemctl stop kristoff || true
systemctl enable --now kristoff

mkdir -p /etc/nginx/ssl /etc/nginx/conf.d
openssl req -x509 -nodes -days 365 -newkey rsa:2048 -keyout /etc/nginx/ssl/kristoff.key -out /etc/nginx/ssl/kristoff.crt -subj "/C=US/ST=State/L=City/O=Kristoff/OU=IT/CN=localhost"
cat <<EOF > /etc/nginx/conf.d/kristoff.conf
server {
    listen 80;
    server_name _;
    location / {
        return 301 https://\$host\$request_uri;
    }
}
server {
    listen 443 ssl default_server;
    listen 8080 ssl;
    server_name _;
    ssl_certificate /etc/nginx/ssl/kristoff.crt;
    ssl_certificate_key /etc/nginx/ssl/kristoff.key;
    error_page 497 https://\$host:\$server_port\$request_uri;
    location / {
        proxy_pass http://127.0.0.1:$APP_PORT;
        proxy_set_header Host \$host;
        proxy_set_header X-Real-IP \$remote_addr;
        proxy_set_header X-Forwarded-For \$proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto \$scheme;
        proxy_read_timeout 300;
        proxy_connect_timeout 300;
    }
}
EOF
rm -f /etc/nginx/conf.d/default.conf || true
nginx -t && systemctl restart nginx
systemctl enable nginx

echo '>>> Checking backend status...'
sleep 5
STATUS=$(curl -k -s -o /dev/null -w "%{http_code}" https://localhost:8080/)
if [ "$STATUS" == "301" ] || [ "$STATUS" == "200" ] || [ "$STATUS" == "404" ]; then
    echo -e "\033[0;32mINSTALLATION COMPLETE (SUCCESS)!\033[0m"
    echo "------------------------------------------------"
    echo "URL:            https://$(hostname -I | awk '{print $1}'):8080"
    echo "Admin Email:    $ADMIN_EMAIL"
    echo "Admin Password: $ADMIN_PASS"
    echo "------------------------------------------------"
else
    echo -e "\033[0;31mERROR: Backend is not responding on 8080 (HTTP $STATUS)\033[0m"
    journalctl -u kristoff -n 20
fi
